logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class ModelLoadError(Exception):
    pass


class ModelVerificationError(Exception):
    pass


class SecureModelLoader:
    def __init__(
        self,
        model_path: Optional[str] = None,
        verification_key: Optional[str] = None,
        allowed_extensions: Optional[list] = None,
        max_model_size_mb: int = 500
    ):
        self.model_path = model_path or os.getenv('MODEL_PATH')
        self.verification_key = verification_key or os.getenv('MODEL_VERIFICATION_KEY')
        self.allowed_extensions = allowed_extensions or ['.pkl', '.h5', '.pt', '.pth', '.onnx', '.pb']
        self.max_model_size_bytes = max_model_size_mb * 1024 * 1024
        self.model = None
        self.model_metadata = {}
        
        if not self.model_path:
            raise ValueError("MODEL_PATH must be provided via parameter or environment variable")
        
        if not self.verification_key:
            logger.warning("MODEL_VERIFICATION_KEY not set - model integrity verification disabled")
            logger.warning("This is NOT recommended for production environments")
        
        self._validate_model_path()
    
    def _validate_model_path(self):
        if not self.model_path:
            raise ValueError("Model path cannot be empty")
        
        path_str = str(self.model_path)
        
        dangerous_patterns = ['..', '~', '$', '`', '|', ';', '&', '>', '<', '\n', '\r']
        for pattern in dangerous_patterns:
            if pattern in path_str:
                raise ValueError(f"Model path contains dangerous pattern: {pattern}")
        
        if path_str.startswith('/etc/') or path_str.startswith('/sys/') or path_str.startswith('/proc/'):
            raise ValueError("Model path points to restricted system directory")
    
    def _verify_file_integrity(self, file_path: str, expected_hash: Optional[str] = None) -> bool:
        if not self.verification_key:
            logger.warning(f"Skipping integrity verification for {file_path} - no verification key provided")
            return True
        
        if not expected_hash:
            metadata_path = f"{file_path}.metadata.json"
            if os.path.exists(metadata_path):
                try:
                    with open(metadata_path, 'r') as f:
                        metadata = json.load(f)
                        expected_hash = metadata.get('sha256_hash')
                except Exception as e:
                    logger.error(f"Failed to read metadata: {e}")
                    raise ModelVerificationError("Cannot verify model without hash")
            else:
                raise ModelVerificationError("No metadata file found for verification")
        
        sha256_hash = hashlib.sha256()
        with open(file_path, 'rb') as f:
            for chunk in iter(lambda: f.read(4096), b''):
                sha256_hash.update(chunk)
        
        computed_hash = sha256_hash.hexdigest()
        
        if computed_hash != expected_hash:
            raise ModelVerificationError(
                f"Model integrity check failed. Expected: {expected_hash}, Got: {computed_hash}"
            )
        
        hmac_signature = hmac.new(
            self.verification_key.encode(),
            computed_hash.encode(),
            hashlib.sha256
        ).hexdigest()
        
        logger.info(f"Model integrity verified successfully (HMAC: {hmac_signature[:16]}...)")
        return True
    
    def _check_file_size(self, file_path: str) -> bool:
        file_size = os.path.getsize(file_path)
        if file_size > self.max_model_size_bytes:
            raise ModelLoadError(
                f"Model file size ({file_size} bytes) exceeds maximum allowed "
                f"({self.max_model_size_bytes} bytes)"
            )
        return True
    
    def _validate_file_extension(self, file_path: str) -> bool:
        ext = Path(file_path).suffix.lower()
        if ext not in self.allowed_extensions:
            raise ModelLoadError(
                f"File extension '{ext}' not in allowed list: {self.allowed_extensions}"
            )
        return True
    
    def _load_model_metadata(self, model_path: str) -> Dict[str, Any]:
        metadata_path = f"{model_path}.metadata.json"
        if not os.path.exists(metadata_path):
            logger.warning(f"No metadata file found at {metadata_path}")
            return {}
        
        try:
            with open(metadata_path, 'r') as f:
                metadata = json.load(f)
            
            required_fields = ['model_version', 'created_at', 'sha256_hash']
            missing_fields = [field for field in required_fields if field not in metadata]
            if missing_fields:
                logger.warning(f"Metadata missing required fields: {missing_fields}")
            
            return metadata
        except Exception as e:
            logger.error(f"Failed to load metadata: {e}")
            return {}
    
    def _safe_load_pickle(self, file_path: str):
        import pickle
        
        class RestrictedUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                safe_modules = {
                    'numpy', 'numpy.core', 'numpy.core.multiarray',
                    'sklearn', 'sklearn.tree', 'sklearn.ensemble',
                    'pandas', 'pandas.core', 'pandas.core.frame',
                    'torch', 'tensorflow', 'keras'
                }
                
                if not any(module.startswith(safe_mod) for safe_mod in safe_modules):
                    raise pickle.UnpicklingError(
                        f"Attempted to load class from untrusted module: {module}.{name}"
                    )
                
                return super().find_class(module, name)
        
        with open(file_path, 'rb') as f:
            return RestrictedUnpickler(f).load()
    
    def _load_model_file(self, file_path: str):
        ext = Path(file_path).suffix.lower()
        
        try:
            if ext == '.pkl':
                return self._safe_load_pickle(file_path)
            elif ext in ['.h5']:
                import tensorflow as tf
                return tf.keras.models.load_model(file_path)
            elif ext in ['.pt', '.pth']:
                import torch
                return torch.load(file_path, map_location='cpu')
            elif ext == '.onnx':
                import onnxruntime as ort
                return ort.InferenceSession(file_path)
            elif ext == '.pb':
                import tensorflow as tf
                return tf.saved_model.load(file_path)
            else:
                raise ModelLoadError(f"Unsupported model format: {ext}")
        except Exception as e:
            logger.error(f"Failed to load model: {e}")
            raise ModelLoadError(f"Model loading failed: {str(e)}")
    
    def load_model(self, model_path: Optional[str] = None) -> Any:
        target_path = model_path or self.model_path
        
        if not os.path.exists(target_path):
            raise ModelLoadError(f"Model file not found: {target_path}")
        
        if not os.path.isfile(target_path):
            raise ModelLoadError(f"Model path is not a file: {target_path}")
        
        logger.info(f"Loading model from: {target_path}")
        
        self._validate_file_extension(target_path)
        self._check_file_size(target_path)
        
        self.model_metadata = self._load_model_metadata(target_path)
        
        expected_hash = self.model_metadata.get('sha256_hash')
        self._verify_file_integrity(target_path, expected_hash)
        
        self.model = self._load_model_file(target_path)
        
        logger.info(f"Model loaded successfully from {target_path}")
        if self.model_metadata:
            logger.info(f"Model version: {self.model_metadata.get('model_version', 'unknown')}")
            logger.info(f"Created at: {self.model_metadata.get('created_at', 'unknown')}")
        
        return self.model
    
    def get_model(self) -> Any:
        if self.model is None:
            raise ModelLoadError("No model loaded. Call load_model() first.")
        return self.model
    
    def get_metadata(self) -> Dict[str, Any]:
        return self.model_metadata.copy()


class ProductionInferenceService:
    def __init__(self):
        self.model_loader = SecureModelLoader(
            max_model_size_mb=int(os.getenv('MAX_MODEL_SIZE_MB', '500'))
        )
        self.model = None
    
    def startup(self):
        logger.info("Starting Production Inference Service...")
        
        try:
            self.model = self.model_loader.load_model()
            logger.info("Service started successfully")
        except Exception as e:
            logger.error(f"Failed to start service: {e}")
            sys.exit(1)
    
    def predict(self, input_data):
        if self.model is None:
            raise RuntimeError("Model not loaded")
        
        return self.model.predict(input_data)
    
    def health_check(self) -> Dict[str, Any]:
        return {
            'status': 'healthy' if self.model is not None else 'unhealthy',
            'model_loaded': self.model is not None,
            'model_metadata': self.model_loader.get_metadata(),
            'timestamp': datetime.utcnow().isoformat()
        }


